I have an Android app that scans multiple barcodes per camera frame using Google ML Kit barcode scanning, and I accumulate the unique values into a list shown on screen. I want to replace ML Kit with Scandit MatrixScan Batch (BarcodeBatch) so I get real multi-barcode tracking. Here is my Activity. Show me the full migrated file.

```kotlin
package com.example.myapp

import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.camera.core.ImageAnalysis
import androidx.camera.core.ImageProxy
import com.google.mlkit.vision.barcode.BarcodeScanning
import com.google.mlkit.vision.barcode.BarcodeScannerOptions
import com.google.mlkit.vision.barcode.common.Barcode
import com.google.mlkit.vision.common.InputImage

class MainActivity : AppCompatActivity() {

    private val scannedValues = mutableListOf<String>()

    private val options = BarcodeScannerOptions.Builder()
        .setBarcodeFormats(
            Barcode.FORMAT_EAN_13,
            Barcode.FORMAT_QR_CODE,
            Barcode.FORMAT_CODE_128
        )
        .build()
    private val scanner = BarcodeScanning.getClient(options)

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // CameraX preview + analysis setup omitted
    }

    private fun analyze(imageProxy: ImageProxy) {
        val mediaImage = imageProxy.image ?: return
        val image = InputImage.fromMediaImage(mediaImage, imageProxy.imageInfo.rotationDegrees)
        scanner.process(image)
            .addOnSuccessListener { barcodes ->
                for (barcode in barcodes) {
                    val value = barcode.rawValue ?: continue
                    if (scannedValues.none { it == value }) {
                        scannedValues.add(value)
                    }
                }
            }
            .addOnCompleteListener { imageProxy.close() }
    }
}
